firmware_template.source:
#include "mq_gas_sensor.h"
#include <Arduino.h>
#define MQ_ANALOG_PIN 34
#define MQ_DIGITAL_PIN 35
#define MQ_THRESHOLD 2000
static int _raw = 0;
static float _ppm = 0;
static bool _alert = false;
static unsigned long _last = 0;
void mq_gas_setup() {
  pinMode(MQ_ANALOG_PIN, INPUT);
  pinMode(MQ_DIGITAL_PIN, INPUT);
  Serial.println("[mq] OK — warm-up 60s");
}
void mq_gas_loop() {
  if (millis()-_last < 1000) return;
  _last = millis();
  _raw = analogRead(MQ_ANALOG_PIN);
  _ppm = (float)_raw / 4095.0f * 1000.0f;
  _alert = !digitalRead(MQ_DIGITAL_PIN);
  if (_alert) Serial.printf("[mq] ALERT! raw=%d ppm=%.0f\n",_raw,_ppm);
}
int mq_gas_get_raw(){return _raw;}
float mq_gas_get_ppm(){return _ppm;}
bool mq_gas_alert(){return _alert;}
